// WF1 v13.0 - EXTRACT DATA WITH 2-STEP LOGIC
// ============================================

const FALLBACK_EMAIL = 'vynnl@esuhai.com';
const ALWAYS_CC = ['hoangkha@esuhai.com', 'vynnl@esuhai.com'];

function safeText(arr) {
  if (!arr || !Array.isArray(arr)) return '';
  return arr.map(t => t.plain_text || '').join('').trim();
}

function safeTitle(arr) {
  return safeText(arr);
}

function safeSelect(obj) {
  return obj?.name || '';
}

function safeDate(obj) {
  return obj?.start || '';
}

function safeRollup(obj) {
  if (!obj) return '';
  if (obj.type === 'array' && obj.array?.[0]) {
    const first = obj.array[0];
    if (first.type === 'email') return first.email || '';
    if (first.type === 'rich_text') return safeText(first.rich_text);
    if (first.type === 'title') return safeTitle(first.title);
  }
  return '';
}

function extractPages(item) {
  const json = item.json;
  if (json.results && Array.isArray(json.results)) return json.results;
  if (json.properties && json.id) return [json];
  return [];
}

const allItems = $input.all();
const results = [];

for (const item of allItems) {
  const pages = extractPages(item);

  for (const page of pages) {
    const props = page.properties;
    const id = page.id;

    // Extract fields
    const tieuDe = safeTitle(props['Tiêu đề']?.title);
    const nguon = safeSelect(props['Nguồn']?.select);
    const tinhTrang = safeSelect(props['TINH_TRANG']?.select);
    const daДуệt = safeSelect(props['✅ Đã duyệt bởi người chỉ đạo']?.select);
    const emailNguoiChiDao = safeRollup(props['Email người chỉ đạo']?.rollup);
    const emailDauMoi = safeRollup(props['Email đầu mối']?.rollup);
    const ngayNhan = safeDate(props['Ngày nhận']?.date);
    const noiDung = safeText(props['Nội dung gốc']?.rich_text);
    const t2 = safeText(props['T2 - NHIỆM VỤ']?.rich_text);
    const t3 = safeText(props['T3 - CHỈ TIÊU']?.rich_text);
    const t4 = safeDate(props['T4 - THỜI HẠN']?.date);

    // Determine STEP
    let step = '';
    let sendTo = '';
    let subject = '';
    let ccTo = '';

    if (!daДуệt || daДуệt === '' || daДуệt === 'Chưa duyệt') {
      // STEP 1: Gửi người chỉ đạo
      step = 'STEP1';
      sendTo = emailNguoiChiDao || FALLBACK_EMAIL;
      subject = `[Cần Duyệt] ${tieuDe || 'Chỉ đạo mới'}`;
      ccTo = ALWAYS_CC.filter(e => e !== sendTo).join(', ');
    } else if (daДуệt === 'Đã duyệt') {
      // STEP 2: Gửi đầu mối
      step = 'STEP2';
      sendTo = emailDauMoi || FALLBACK_EMAIL;
      subject = `[Cần Làm Rõ] ${tieuDe || 'Chỉ đạo'} - Hạn: ${t4 || 'Chưa xác định'}`;
      const ccList = new Set(ALWAYS_CC);
      if (emailNguoiChiDao) ccList.add(emailNguoiChiDao);
      ccList.delete(sendTo);
      ccTo = Array.from(ccList).join(', ');
    } else {
      continue; // Skip if rejected
    }

    results.push({
      json: {
        clarificationId: id,
        step,
        tieuDe,
        nguon,
        ngayNhan,
        noiDung,
        t2, t3, t4,
        sendTo,
        emailSubject: subject,
        ccTo,
        emailNguoiChiDao,
        emailDauMoi,
        version: '13.0'
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { warning: true, message: 'No items to process', sendTo: '', emailSubject: '' } }];
}

return results;

